    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        n = len(s)
        la, lb = len(a), len(b)

        # Find all start positions where a occurs
        posA = []
        for i in range(n - la + 1):
            if s[i:i + la] == a:
