class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        n = len(s)
        la, lb = len(a), len(b)

        # Find all start indices where a matches and where b matches
        idx_a = []
        for i in range(0, n - la + 1):
            if s[i:i + la] == a:
                idx_a.append(i)

        idx_b = []
        for j in range(0, n - lb + 1):
            if s[j:j + lb] == b:
                idx_b.append(j)

        # If no b matches, no i can be beautiful
        if not idx_b:
            return []

        # Two pointers to check existence of j with |j - i| <= k
        res = []
        p = 0  # first b index with idx_b[p] >= i-k
        q = 0  # last b index with idx_b[q] <= i+k (we'll move q as needed)

        for i in idx_a:
            left = i - k
            right = i + k

            while p < len(idx_b) and idx_b[p] < left:
                p += 1
            if q < p:
                q = p
            while q < len(idx_b) and idx_b[q] <= right:
                q += 1

            # if there is at least one idx_b in [left, right], then i is beautiful
            if p < q:
                res.append(i)

        return res
